window.addEventListener("load", () => {
  const t = document.querySelectorAll("iframe"),
    e = document.querySelector("#instagram-title-injection");
  let n = JSON.parse(e.dataset.json);
  const r = [];
  let i = 0;
  for (let t in n) n[t].length > 0 && r.push(n[t]);
  t.length > 0 &&
    r.length > 0 &&
    t.forEach((t) => {
      const e = t.hasAttribute("title"),
        n = t.getAttribute("src"),
        o = ["instagram", "tiktok", "twitter"].includes(extractDomain(n));
      ((t && !e && o && r[i]) || (t && e && o && r[i])) && (t.setAttribute("title", r[i]), i++);
    });
});
const extractDomain = (t) => {
  if (!t) return;
  const e = t.match(/(twitter|instagram|tiktok|youtube|facebook|snapchat)\.com/);
  return e ? e[1] : null;
};